using UnityEngine;\nusing UnityEngine.UI;\nusing TMPro;\n\npublic class ProfileSetupUI : MonoBehaviour\n{\n    [SerializeField] private Canvas setupPanel;\n    [SerializeField] private InputField playerNameInput;\n    [SerializeField] private Dropdown countryDropdown;\n    [SerializeField] private Button confirmButton;\n    [SerializeField] private Button skipButton;\n    [SerializeField] private TextMeshProUGUI previewText;\n\n    private void Start()\n    {\n        if (confirmButton != null)\n            confirmButton.onClick.AddListener(ConfirmProfile);\n        \n        if (skipButton != null)\n            skipButton.onClick.AddListener(SkipSetup);\n\n        if (playerNameInput != null)\n            playerNameInput.onValueChanged.AddListener(OnNameChanged);\n\n        if (countryDropdown != null)\n            countryDropdown.onValueChanged.AddListener(OnCountryChanged);\n\n        SetupCountryDropdown();\n        CheckIfFirstTime();\n    }\n\n    private void CheckIfFirstTime()\n    {\n        if (setupPanel != null)\n        {\n            bool isFirstTime = !PlayerPrefs.HasKey(\"PlayerName\");\n            setupPanel.gameObject.SetActive(isFirstTime);\n        }\n    }\n\n    private void SetupCountryDropdown()\n    {\n        if (countryDropdown == null)\n            return;\n\n        countryDropdown.ClearOptions();\n        var countryOptions = new System.Collections.Generic.List<string>\n        {\n            \"🇺🇸 United States\",\n            \"🇮🇳 India\",\n            \"🇬🇧 United Kingdom\",\n            \"🇨🇦 Canada\",\n            \"🇦🇺 Australia\",\n            \"🇫🇷 France\",\n            \"🇩🇪 Germany\",\n            \"🇯🇵 Japan\",\n            \"🇧🇷 Brazil\",\n            \"🇲🇽 Mexico\",\n            \"🇨🇳 China\",\n            \"🇷🇺 Russia\",\n            \"🇰🇷 South Korea\",\n            \"🇳🇿 New Zealand\",\n            \"🇸🇬 Singapore\",\n            \"🇵🇰 Pakistan\",\n            \"🇧🇩 Bangladesh\",\n            \"🇿🇦 South Africa\",\n            \"🇳🇬 Nigeria\",\n            \"🇦🇷 Argentina\",\n        };\n        countryDropdown.AddOptions(countryOptions);\n    }\n\n    private void OnNameChanged(string newName)\n    {\n        UpdatePreview();\n    }\n\n    private void OnCountryChanged(int selectedIndex)\n    {\n        UpdatePreview();\n    }\n\n    private void UpdatePreview()\n    {\n        if (previewText != null)\n        {\n            string name = playerNameInput != null ? playerNameInput.text : \"Player\";\n            string country = countryDropdown != null ? countryDropdown.options[countryDropdown.value].text : \"🌍\";\n            previewText.text = $\"Preview: {country} {name}\";\n        }\n    }\n\n    private void ConfirmProfile()\n    {\n        string playerName = playerNameInput != null ? playerNameInput.text : \"Player\";\n        if (string.IsNullOrEmpty(playerName))\n        {\n            playerName = \"Player\";\n        }\n\n        string countryCode = GetCountryCodeFromDropdown();\n\n        if (PlayerProfileManager.Instance != null)\n        {\n            PlayerProfileManager.Instance.SetPlayerName(playerName);\n            PlayerProfileManager.Instance.SetCountry(countryCode);\n        }\n\n        Debug.Log($\"Profile set: {playerName} from {countryCode}\");\n        \n        if (setupPanel != null)\n        {\n            setupPanel.gameObject.SetActive(false);\n        }\n    }\n\n    private void SkipSetup()\n    {\n        Debug.Log(\"Profile setup skipped\");\n        if (setupPanel != null)\n        {\n            setupPanel.gameObject.SetActive(false);\n        }\n    }\n\n    private string GetCountryCodeFromDropdown()\n    {\n        string selectedCountry = countryDropdown != null ? countryDropdown.options[countryDropdown.value].text : \"US\";\n        \n        // Extract country code from emoji and name\n        var countryMap = new System.Collections.Generic.Dictionary<string, string>\n        {\n            { \"United States\", \"US\" }, { \"India\", \"IN\" }, { \"United Kingdom\", \"GB\" },\n            { \"Canada\", \"CA\" }, { \"Australia\", \"AU\" }, { \"France\", \"FR\" },\n            { \"Germany\", \"DE\" }, { \"Japan\", \"JP\" }, { \"Brazil\", \"BR\" },\n            { \"Mexico\", \"MX\" }, { \"China\", \"CN\" }, { \"Russia\", \"RU\" },\n            { \"South Korea\", \"KR\" }, { \"New Zealand\", \"NZ\" }, { \"Singapore\", \"SG\" },\n            { \"Pakistan\", \"PK\" }, { \"Bangladesh\", \"BD\" }, { \"South Africa\", \"ZA\" },\n            { \"Nigeria\", \"NG\" }, { \"Argentina\", \"AR\" },\n        };\n\n        foreach (var kvp in countryMap)\n        {\n            if (selectedCountry.Contains(kvp.Key))\n            {\n                return kvp.Value;\n            }\n        }\n\n        return \"US\";\n    }\n}\n"